import React, { useState, useEffect, useRef } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const NUM = 5;
const INIT = [1, 2, 3, 4, 5];
const PRESETS = [
  { name: 'Linear', values: [1, 2, 3, 4, 5] },
  { name: 'Uniform', values: [3, 3, 3, 3, 3] },
  { name: 'Outlier', values: [1, 2, 2, 3, 9] },
  { name: 'Spread', values: [-4, -1, 0, 2, 5] },
];

const STEP_LABELS = ['Input', 'Min & Max', 'Normalize', 'Result'];

const W = 540, SVG_H = 310;
const TOP = { y: 12, h: 115 };
const BOT = { y: 195, h: 95 };
const AXIS_PAD = 46;
const BAR_GAP = (W - AXIS_PAD - 15) / NUM;
const BAR_W = 40;
const barCX = (i) => AXIS_PAD + BAR_GAP * (i + 0.5);

const Y_MIN = -5, Y_MAX = 10;
const valToY = (v) => TOP.y + TOP.h * (1 - (v - Y_MIN) / (Y_MAX - Y_MIN));
const yToVal = (y) => Y_MIN + (1 - (y - TOP.y) / TOP.h) * (Y_MAX - Y_MIN);
const normToY = (v) => BOT.y + BOT.h * (1 - v);

export default function App() {
  const [values, setValues] = useState([...INIT]);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [dragIdx, setDragIdx] = useState(null);
  const [hovered, setHovered] = useState(null);
  const svgRef = useRef(null);

  const xMin = Math.min(...values);
  const xMax = Math.max(...values);
  const range = xMax - xMin;
  const isUniform = range === 0;
  const normalized = values.map((v) =>
    isUniform ? 0 : Math.round(((v - xMin) / range) * 10000) / 10000
  );

  const minIndices = values.reduce((a, v, i) => (v === xMin ? [...a, i] : a), []);
  const maxIndices = values.reduce((a, v, i) => (v === xMax ? [...a, i] : a), []);

  useEffect(() => {
    if (!playing) return;
    const t = setTimeout(() => {
      if (step < 3) setStep((s) => s + 1);
      else { setPlaying(false); }
    }, 1800);
    return () => clearTimeout(t);
  }, [playing, step]);

  useEffect(() => {
    if (dragIdx === null) return;
    const handleMove = (e) => {
      e.preventDefault();
      const svg = svgRef.current;
      if (!svg) return;
      const rect = svg.getBoundingClientRect();
      const scaleY = SVG_H / rect.height;
      const clientY = e.touches ? e.touches[0].clientY : e.clientY;
      const y = (clientY - rect.top) * scaleY;
      const raw = yToVal(y);
      const snapped = Math.round(raw * 2) / 2;
      const clamped = Math.max(Y_MIN, Math.min(Y_MAX, snapped));
      setValues((prev) => prev.map((v, i) => (i === dragIdx ? clamped : v)));
    };
    const handleUp = () => setDragIdx(null);
    window.addEventListener('mousemove', handleMove);
    window.addEventListener('mouseup', handleUp);
    window.addEventListener('touchmove', handleMove, { passive: false });
    window.addEventListener('touchend', handleUp);
    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('mouseup', handleUp);
      window.removeEventListener('touchmove', handleMove);
      window.removeEventListener('touchend', handleUp);
    };
  }, [dragIdx]);

  const handleBarDown = (e, i) => {
    e.preventDefault();
    setDragIdx(i);
  };

  const handleReset = () => {
    setValues([...INIT]);
    setStep(0);
    setPlaying(false);
    setHovered(null);
  };

  const handlePlay = () => {
    if (playing) { setPlaying(false); return; }
    if (step >= 3) setStep(0);
    setPlaying(true);
  };

  const getBarColor = (i) => {
    if (step >= 1 && !isUniform) {
      if (maxIndices.includes(i)) return theme.colors.pink;
      if (minIndices.includes(i)) return theme.colors.yellow;
    }
    return theme.colors.blue;
  };

  const zeroY = valToY(0);
  const minLineY = valToY(xMin);
  const maxLineY = valToY(xMax);

  const focusIdx = hovered !== null ? hovered : null;

  const getInsight = () => {
    if (isUniform) return 'All values are identical! max = min, so division by zero -> all outputs are 0.0.';
    if (step === 0) return 'Drag the bars up or down to change input values. Watch how normalization responds!';
    if (step === 1) return `Min = ${xMin}, Max = ${xMax}, Range = ${xMax} - ${xMin} = ${range}. These anchor the [0, 1] scale.`;
    if (step === 2) return `Each value: (x - ${xMin}) / ${range}. The min maps to 0.0, the max maps to 1.0.`;
    return `Result: [${normalized.join(', ')}]. All values are now in [0, 1], preserving relative order.`;
  };

  return (
    <div style={{
      fontFamily: theme.font,
      background: theme.colors.background,
      color: theme.colors.text,
      maxWidth: 600,
      margin: '0 auto',
      padding: '16px 20px',
      minHeight: '100vh',
      boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
        <div>
          <div style={{ fontSize: 17, fontWeight: 700 }}>Min-Max Normalization</div>
          <div style={{ fontSize: 11, color: theme.colors.textMuted, marginTop: 2 }}>Scale values to [0, 1]</div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button onClick={handlePlay} style={{
            background: playing ? theme.colors.primary + '33' : theme.colors.primary,
            color: '#fff', border: 'none', borderRadius: 6, padding: '5px 12px',
            fontSize: 11, fontFamily: theme.font, cursor: 'pointer', fontWeight: 600,
          }}>{playing ? 'Pause' : 'Play'}</button>
          <button onClick={handleReset} style={{
            background: theme.colors.surfaceAlt, color: theme.colors.textSecondary,
            border: '1px solid ' + theme.colors.border, borderRadius: 6, padding: '5px 10px',
            fontSize: 11, fontFamily: theme.font, cursor: 'pointer',
          }}>Reset</button>
        </div>
      </div>

      {/* Step indicators */}
      <div style={{ display: 'flex', gap: 4, marginBottom: 12 }}>
        {STEP_LABELS.map((label, i) => (
          <button key={i} onClick={() => { setStep(i); setPlaying(false); }} style={{
            flex: 1, padding: '5px 0', fontSize: 10, fontFamily: theme.font,
            background: step === i ? theme.colors.primary + '22' : theme.colors.surface,
            color: step === i ? theme.colors.primary : theme.colors.textMuted,
            border: step === i ? '1px solid ' + theme.colors.primary + '55' : '1px solid ' + theme.colors.border,
            borderRadius: 6, cursor: 'pointer', fontWeight: step === i ? 700 : 400,
            transition: 'all 0.3s ease',
          }}>{label}</button>
        ))}
      </div>

      {/* Main SVG */}
      <div style={{
        background: theme.colors.surface, borderRadius: 10,
        border: '1px solid ' + theme.colors.border, padding: '8px 10px',
        marginBottom: 10, position: 'relative',
      }}>
        <svg ref={svgRef} viewBox={`0 0 ${W} ${SVG_H}`}
          style={{ width: '100%', height: 'auto', display: 'block', cursor: dragIdx !== null ? 'grabbing' : 'default', userSelect: 'none' }}>

          {/* Top chart: Original Values */}
          <text x={W / 2} y={TOP.y + 2} textAnchor="middle" fill={theme.colors.textMuted} fontSize="9" fontFamily={theme.font}>ORIGINAL VALUES (drag bars)</text>

          {/* Top Y axis */}
          <line x1={AXIS_PAD - 4} y1={TOP.y + 10} x2={AXIS_PAD - 4} y2={TOP.y + TOP.h} stroke={theme.colors.border} strokeWidth="1" />
          {[-4, -2, 0, 2, 4, 6, 8, 10].map((v) => {
            const y = valToY(v);
            if (y < TOP.y + 8 || y > TOP.y + TOP.h) return null;
            return <g key={v}>
              <line x1={AXIS_PAD - 8} y1={y} x2={AXIS_PAD - 4} y2={y} stroke={theme.colors.border} strokeWidth="1" />
              <text x={AXIS_PAD - 12} y={y + 3} textAnchor="end" fill={theme.colors.textMuted} fontSize="8" fontFamily={theme.font}>{v}</text>
            </g>;
          })}

          {/* Zero line */}
          <line x1={AXIS_PAD} y1={zeroY} x2={W - 10} y2={zeroY} stroke={theme.colors.textMuted} strokeWidth="0.5" strokeDasharray="3,3" opacity="0.4" />

          {/* Min/Max lines (step >= 1) */}
          {step >= 1 && !isUniform && <>
            <line x1={AXIS_PAD} y1={minLineY} x2={W - 10} y2={minLineY}
              stroke={theme.colors.yellow} strokeWidth="1" strokeDasharray="4,3" opacity="0.6">
              <animate attributeName="opacity" values="0.3;0.7;0.3" dur="2s" repeatCount="indefinite" />
            </line>
            <text x={W - 12} y={minLineY - 4} textAnchor="end" fill={theme.colors.yellow} fontSize="9" fontFamily={theme.font} fontWeight="600">min={xMin}</text>
            <line x1={AXIS_PAD} y1={maxLineY} x2={W - 10} y2={maxLineY}
              stroke={theme.colors.pink} strokeWidth="1" strokeDasharray="4,3" opacity="0.6">
              <animate attributeName="opacity" values="0.3;0.7;0.3" dur="2s" repeatCount="indefinite" />
            </line>
            <text x={W - 12} y={maxLineY + 12} textAnchor="end" fill={theme.colors.pink} fontSize="9" fontFamily={theme.font} fontWeight="600">max={xMax}</text>
          </>}

          {/* Input bars */}
          {values.map((v, i) => {
            const cx = barCX(i);
            const top = Math.min(zeroY, valToY(v));
            const barH = Math.abs(valToY(v) - zeroY);
            const col = getBarColor(i);
            const isHov = hovered === i;
            const isDrag = dragIdx === i;
            return <g key={i}
              onMouseDown={(e) => handleBarDown(e, i)}
              onTouchStart={(e) => handleBarDown(e, i)}
              onMouseEnter={() => setHovered(i)}
              onMouseLeave={() => setHovered(null)}
              style={{ cursor: 'grab' }}>
              {/* Hit area */}
              <rect x={cx - BAR_W / 2 - 6} y={TOP.y + 8} width={BAR_W + 12} height={TOP.h - 6}
                fill="transparent" />
              {/* Bar */}
              <rect x={cx - BAR_W / 2} y={top} width={BAR_W} height={Math.max(barH, 2)}
                rx="4" fill={col} opacity={isHov || isDrag ? 1 : 0.8}
                style={{ transition: dragIdx !== null ? 'none' : 'all 0.3s ease', filter: isDrag ? 'brightness(1.3)' : 'none' }} />
              {/* Drag handle dots */}
              <circle cx={cx} cy={valToY(v)} r={isDrag ? 5 : 3.5} fill={col}
                stroke={theme.colors.background} strokeWidth="1.5"
                style={{ transition: dragIdx !== null ? 'none' : 'all 0.3s ease' }} />
              {/* Value label */}
              <text x={cx} y={valToY(v) + (v >= 0 ? -8 : 14)} textAnchor="middle"
                fill={col} fontSize={isHov ? '11' : '10'} fontFamily={theme.font} fontWeight="700"
                style={{ transition: 'all 0.2s ease' }}>{v}</text>
            </g>;
          })}

          {/* Connector area */}
          <line x1={AXIS_PAD} y1={155} x2={W - 10} y2={155} stroke={theme.colors.border} strokeWidth="0.5" />

          {/* Formula display */}
          {step >= 2 && !isUniform && (
            <text x={W / 2} y={170} textAnchor="middle" fill={theme.colors.textSecondary} fontSize="10" fontFamily={theme.font}>
              {focusIdx !== null
                ? `(${values[focusIdx]} - ${xMin}) / ${range} = ${normalized[focusIdx]}`
                : `X' = (X - ${xMin}) / (${xMax} - ${xMin})`
              }
            </text>
          )}
          {step >= 2 && isUniform && (
            <text x={W / 2} y={170} textAnchor="middle" fill={theme.colors.yellow} fontSize="10" fontFamily={theme.font}>
              max = min -> all values become 0.0
            </text>
          )}
          {step < 2 && (
            <text x={W / 2} y={170} textAnchor="middle" fill={theme.colors.textMuted} fontSize="10" fontFamily={theme.font}>
              X' = (X - min) / (max - min)
            </text>
          )}

          {/* Connecting lines */}
          {step >= 2 && values.map((v, i) => {
            const cx = barCX(i);
            return <line key={i} x1={cx} y1={155} x2={cx} y2={BOT.y}
              stroke={theme.colors.green} strokeWidth={hovered === i ? 1.5 : 0.7}
              strokeDasharray="2,2" opacity={hovered === i ? 0.8 : 0.3}
              style={{ transition: 'all 0.3s ease' }} />;
          })}

          {/* Bottom chart: Normalized Values */}
          <text x={W / 2} y={BOT.y - 2} textAnchor="middle" fill={theme.colors.textMuted} fontSize="9" fontFamily={theme.font}>NORMALIZED [0, 1]</text>

          {/* Bottom Y axis */}
          <line x1={AXIS_PAD - 4} y1={BOT.y + 6} x2={AXIS_PAD - 4} y2={BOT.y + BOT.h} stroke={theme.colors.border} strokeWidth="1" />
          {[0, 0.25, 0.5, 0.75, 1.0].map((v) => {
            const y = normToY(v);
            return <g key={v}>
              <line x1={AXIS_PAD - 8} y1={y} x2={AXIS_PAD - 4} y2={y} stroke={theme.colors.border} strokeWidth="1" />
              <text x={AXIS_PAD - 12} y={y + 3} textAnchor="end" fill={theme.colors.textMuted} fontSize="8" fontFamily={theme.font}>{v}</text>
              <line x1={AXIS_PAD} y1={y} x2={W - 10} y2={y} stroke={theme.colors.border} strokeWidth="0.3" opacity="0.3" />
            </g>;
          })}

          {/* Output bars */}
          {normalized.map((nv, i) => {
            const cx = barCX(i);
            const barH = Math.max(BOT.h * nv, 1);
            const topY = BOT.y + BOT.h - barH;
            const isHov = hovered === i;
            const show = step >= 2;
            const baseOpacity = show ? (isHov ? 1 : 0.75) : 0.15;
            return <g key={i}
              onMouseEnter={() => setHovered(i)}
              onMouseLeave={() => setHovered(null)}>
              <rect x={cx - BAR_W / 2} y={topY} width={BAR_W} height={barH}
                rx="4" fill={theme.colors.green} opacity={baseOpacity}
                style={{ transition: 'all 0.4s ease' }} />
              {show && (
                <text x={cx} y={topY - 5} textAnchor="middle"
                  fill={theme.colors.green} fontSize={isHov ? '11' : '9'} fontFamily={theme.font}
                  fontWeight="700" opacity={isHov ? 1 : 0.8}
                  style={{ transition: 'all 0.2s ease' }}>{nv}</text>
              )}
            </g>;
          })}

          {/* Index labels */}
          {values.map((_, i) => (
            <text key={i} x={barCX(i)} y={BOT.y + BOT.h + 14} textAnchor="middle"
              fill={hovered === i ? theme.colors.text : theme.colors.textMuted}
              fontSize="9" fontFamily={theme.font}
              style={{ transition: 'color 0.2s' }}>x{i + 1}</text>
          ))}
        </svg>
      </div>

      {/* Presets */}
      <div style={{ display: 'flex', gap: 6, marginBottom: 10 }}>
        <span style={{ fontSize: 10, color: theme.colors.textMuted, lineHeight: '26px', marginRight: 2 }}>Try:</span>
        {PRESETS.map((p) => (
          <button key={p.name} onClick={() => { setValues([...p.values]); setStep(0); setPlaying(false); }}
            style={{
              flex: 1, padding: '4px 0', fontSize: 10, fontFamily: theme.font,
              background: JSON.stringify(values) === JSON.stringify(p.values) ? theme.colors.primary + '22' : theme.colors.surfaceAlt,
              color: JSON.stringify(values) === JSON.stringify(p.values) ? theme.colors.primary : theme.colors.textSecondary,
              border: '1px solid ' + theme.colors.border, borderRadius: 6, cursor: 'pointer',
            }}>{p.name}</button>
        ))}
      </div>

      {/* Computation detail for hovered bar */}
      {hovered !== null && step >= 2 && !isUniform && (
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: 8, padding: '8px 12px',
          border: '1px solid ' + theme.colors.border, marginBottom: 8, textAlign: 'center',
          fontSize: 11, transition: 'all 0.3s ease',
        }}>
          <span style={{ color: getBarColor(hovered) }}>x{hovered + 1} = {values[hovered]}</span>
          <span style={{ color: theme.colors.textMuted }}>{' -> '}</span>
          <span style={{ color: theme.colors.textSecondary }}>({values[hovered]} - {xMin}) / ({xMax} - {xMin})</span>
          <span style={{ color: theme.colors.textMuted }}> = </span>
          <span style={{ color: theme.colors.green, fontWeight: 700 }}>{normalized[hovered]}</span>
        </div>
      )}

      {/* Dynamic insight */}
      <div style={{
        background: theme.colors.surface, borderRadius: 8, padding: '10px 14px',
        fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.6,
        borderLeft: '3px solid ' + (
          step === 0 ? theme.colors.blue : step === 1 ? theme.colors.yellow : step === 2 ? theme.colors.pink : theme.colors.green
        ),
        transition: 'border-color 0.3s',
      }}>
        <span style={{
          color: step === 0 ? theme.colors.blue : step === 1 ? theme.colors.yellow : step === 2 ? theme.colors.pink : theme.colors.green,
          fontWeight: 600,
        }}>
          {step === 0 ? 'Explore: ' : step === 1 ? 'Identify: ' : step === 2 ? 'Compute: ' : 'Result: '}
        </span>
        {getInsight()}
      </div>
    </div>
  );
}
